TEST_CASE( "zone_sort_no_items_to_sort_cleans_up_viewport", "[zones][viewport][activities]" )
{
    avatar &dummy = get_avatar();
    map &here = get_map();

    clear_avatar();
    clear_map();
    zone_manager::get_manager().clear();

    // Scenario: items are NOT in the unsorted zone. The unsorted zone exists
    // nearby. Player presses 'O' to sort but there's nothing to sort at the
    // unsorted zone tile. The activity should end cleanly and the viewport
    // should be deactivated.

    const tripoint_bub_ms start_pos( 60, 61, 0 );
    dummy.setpos( here, start_pos );
    dummy.clear_destination();
    dummy.zone_sort_viewport = avatar::zone_sort_viewport_t{};

    // Unsorted zone at (60,60) — one tile north of player
    const tripoint_bub_ms unsorted_pos( 60, 60, 0 );
    here.ter_set( unsorted_pos, ter_t_floor );
    create_tile_zone( "Unsorted", zone_type_LOOT_UNSORTED, here.get_abs( unsorted_pos ) );

    // Destination zone further away at (60,55)
    const tripoint_bub_ms dest_pos( 60, 55, 0 );
    here.ter_set( dest_pos, ter_t_floor );
    create_tile_zone( "Food", zone_type_LOOT_FOOD, here.get_abs( dest_pos ) );

    // Items are NOT at the unsorted zone — they're at the player's tile (60,61)
    here.add_item_or_charges( start_pos, item( itype_test_apple ) );

    here.invalidate_map_cache( 0 );
    here.build_map_cache( 0, true );

    SECTION( "items not in unsorted zone — viewport deactivates after empty sort" ) {
        CHECK_FALSE( dummy.zone_sort_viewport.active );

        dummy.assign_activity( zone_sort_activity_actor() );

        // Run to completion
        int turns = 0;
        while( dummy.activity && turns < 200 ) {
            dummy.mod_moves( dummy.get_speed() );
            while( dummy.get_moves() > 0 && dummy.activity ) {
                dummy.activity.do_turn( dummy );
            }
            turns++;
        }

        CHECK( turns < 200 );  // Should finish without hanging
        CHECK_FALSE( dummy.activity );
        // The viewport should be deactivated after the activity completes
        // with nothing to sort.
        INFO( "viewport was left active even though no items were sorted" );
        CHECK_FALSE( dummy.zone_sort_viewport.active );
    }

    SECTION( "items in unsorted zone but no matching destination — viewport deactivates" ) {
        // Clear and re-setup: place item IN the unsorted zone, but no matching
        // destination zone (only PFOOD zone exists, apple is food not PFOOD)
        clear_map();
        zone_manager::get_manager().clear();
        dummy.zone_sort_viewport = avatar::zone_sort_viewport_t{};

        const tripoint_bub_ms unsorted_p( 60, 60, 0 );
        here.ter_set( unsorted_p, ter_t_floor );
        create_tile_zone( "Unsorted", zone_type_LOOT_UNSORTED, here.get_abs( unsorted_p ) );

        const tripoint_bub_ms dest_p( 60, 55, 0 );
        here.ter_set( dest_p, ter_t_floor );
        // Only PFOOD zone (perishable food). Apple is standard food, not PFOOD.
        create_tile_zone( "PFood", zone_type_LOOT_PFOOD, here.get_abs( dest_p ) );

        dummy.setpos( here, start_pos );
        dummy.clear_destination();

        // Item IN the unsorted zone — but no destination that matches it
        here.add_item_or_charges( unsorted_p, item( itype_test_apple ) );

        here.invalidate_map_cache( 0 );
        here.build_map_cache( 0, true );

        CHECK_FALSE( dummy.zone_sort_viewport.active );

        dummy.assign_activity( zone_sort_activity_actor() );

        // Run to completion
        int turns = 0;
        while( dummy.activity && turns < 200 ) {
            dummy.mod_moves( dummy.get_speed() );
            while( dummy.get_moves() > 0 && dummy.activity ) {
                dummy.activity.do_turn( dummy );
            }
            turns++;
        }

        CHECK( turns < 200 );
        CHECK_FALSE( dummy.activity );
        INFO( "viewport was left active even though item had no matching destination" );
        CHECK_FALSE( dummy.zone_sort_viewport.active );
    }
}

