{
    heat_activity_actor actor;
    JsonObject data = jsin.get_object();
    data.read( "to_heat", actor.to_heat );
    data.read( "time", actor.requirements.time );
    data.read( "ammo", actor.requirements.ammo );


    if( data.has_member( "heater_data" ) ) {
